import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api';
import './StudentDashboard.css'; // Reuse dashboard styles for cards/charts

export default function StudentInsights() {
    const { studentId } = useParams();
    const navigate = useNavigate();
    const [student, setStudent] = useState(null);
    const [results, setResults] = useState([]);
    const [loading, setLoading] = useState(true);
    const [selectedResult, setSelectedResult] = useState(null);
    const fileInputRef = useRef(null);

    useEffect(() => {
        Promise.all([
            api.get(`/users/${studentId}`),
            api.get(`/results/student/${studentId}`)
        ])
            .then(([userRes, resRes]) => {
                setStudent(userRes.data);
                setResults(resRes.data);
            })
            .catch(err => {
                console.error(err);
            })
            .finally(() => setLoading(false));
    }, [studentId]);

    const handleUploadClick = (e) => {
        e.stopPropagation();
        fileInputRef.current.click();
    };

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            alert(`File "${file.name}" selected for upload!`);
        }
    };

    if (loading) return <div className="page-loading">Loading student data...</div>;
    if (!student) return <div className="page-loading">Student not found.</div>;

    return (
        <div className="student-dashboard">
            <input
                type="file"
                ref={fileInputRef}
                onChange={handleFileChange}
                style={{ display: 'none' }}
            />
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '32px' }}>
                <div>
                    <button onClick={() => navigate(-1)} className="btn btn-secondary btn-sm" style={{ marginBottom: '16px' }}>
                        ← Back to Students
                    </button>
                    <h1 className="page-title">{student.name}'s Profile</h1>
                    <p className="page-desc">{student.course} • {student.department} • Roll: {student.rollNumber}</p>
                </div>
                <div className="activity-status" style={{ fontSize: '1rem' }}>
                    <span className="status-dot"></span> Active Student
                </div>
            </div>

            <div className="stats-grid">
                <div className="stat-card color-1">
                    <div className="stat-label">Assignments Taken</div>
                    <div className="stat-value">{results.length}</div>
                </div>
                <div className="stat-card color-2">
                    <div className="stat-label">Average Score</div>
                    <div className="stat-value">
                        {results.length ? Math.round(results.reduce((a, b) => a + b.percentage, 0) / results.length) : 0}%
                    </div>
                </div>
                <div className="stat-card color-3">
                    <div className="stat-label">Recent Score</div>
                    <div className="stat-value">{results[0]?.percentage || 0}%</div>
                </div>
            </div>

            <div className="dashboard-grid">
                <div className="card chart-card" style={{ gridColumn: 'span 2' }}>
                    <h2>Assignment History</h2>
                    <div className="reports-table-wrap" style={{ marginTop: '20px' }}>
                        <table className="reports-table">
                            <thead>
                                <tr>
                                    <th>Subject</th>
                                    <th>Score</th>
                                    <th>Date</th>
                                    <th style={{ textAlign: 'right' }}>Upload</th>
                                </tr>
                            </thead>
                            <tbody>
                                {results.map((r) => (
                                    <tr key={r._id}>
                                        <td>
                                            <strong
                                                className="subject-link"
                                                style={{ cursor: 'pointer', color: '#10b981' }}
                                                onClick={() => setSelectedResult(r)}
                                            >
                                                {r.subject?.name || r.subject || 'N/A'}
                                            </strong>
                                        </td>
                                        <td><span className="percentage-tag">{r.percentage}%</span></td>
                                        <td>{r.completedAt ? new Date(r.completedAt).toLocaleDateString() : '—'}</td>
                                        <td style={{ textAlign: 'right' }}>
                                            <button
                                                className="upload-btn-mini"
                                                onClick={(e) => { e.stopPropagation(); alert(`Upload for ${r.subject?.name || 'subject'} coming soon!`); }}
                                                title="Upload Assignment"
                                            >
                                                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ width: 16, height: 16 }}>
                                                    <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                                                    <polyline points="17 8 12 3 7 8"></polyline>
                                                    <line x1="12" y1="3" x2="12" y2="15"></line>
                                                </svg>
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                                {results.length === 0 && (
                                    <tr>
                                        <td colSpan="4" className="no-data">No assignment data available for this student.</td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>

            {selectedResult && (
                <div className="modal-overlay" onClick={() => setSelectedResult(null)}>
                    <div className="modal glass-card" onClick={e => e.stopPropagation()}>
                        <div className="modal-header">
                            <h3>Assignment Result</h3>
                            <button className="btn-close" onClick={() => setSelectedResult(null)}>✕</button>
                        </div>
                        <div className="modal-body">
                            <div className="result-summary">
                                <div className="summary-item">
                                    <label>Subject</label>
                                    <span>{selectedResult.subject?.name || selectedResult.subject}</span>
                                </div>
                                <div className="summary-item">
                                    <label>Assignment</label>
                                    <span>{selectedResult.assessment?.title}</span>
                                </div>
                                <div className="summary-item">
                                    <label>Score</label>
                                    <span className="score-high">{selectedResult.percentage}%</span>
                                </div>
                                <div className="summary-item">
                                    <label>Completed On</label>
                                    <span>{new Date(selectedResult.completedAt).toLocaleString()}</span>
                                </div>
                            </div>

                            <div className="result-details">
                                <h4>Performance Breakdown</h4>
                                <p>Student answered <strong>{selectedResult.score}</strong> correct out of <strong>{selectedResult.totalQuestions}</strong> questions.</p>
                                <div className="progress-bar-wrap">
                                    <div className="progress-bar-fill" style={{ width: `${selectedResult.percentage}%` }}></div>
                                </div>
                            </div>
                        </div>
                        <div className="modal-footer">
                            <button className="btn btn-primary" onClick={() => setSelectedResult(null)}>Close</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
